// ============================================================
// Screening Throttle Queue
// ------------------------------------------------------------
// Sits between the Grant Fetch Process Chunk workflow and the
// Grant Eligibility Screener + Tracker workflow.
//
// Producers POST a batch of grant payloads to /webhook/screen-queue.
// This Code node forwards them to /webhook/screen-grant one at a time
// with a small delay between calls, so the Screening workflow's
// AI node cannot burst past OpenAI's TPM limit.
//
// Expected input shape (body):
//   { "grants": [ { url, grantid, orgId, grantData }, ... ] }
// If the body itself is an array, or a single grant object, that is
// also accepted.
// ============================================================

const DELAY_MS    = 300;
const MAX_RETRIES = 5;
const TIMEOUT_MS  = 120000;
const SCREEN_URL  = 'https://n8n.thebrownmine.com/webhook/screen-grant';

const helpers = this.helpers;
const raw = $input.first().json;
const input = raw.body || raw;

let grants;
if (Array.isArray(input)) {
  grants = input;
} else if (Array.isArray(input.grants)) {
  grants = input.grants;
} else if (input && (input.grantid || input.grantData || input.url)) {
  grants = [input];
} else {
  grants = [];
}

let ok = 0;
let failed = 0;
const errors = [];

async function forwardOne(payload, attempt) {
  attempt = attempt || 0;
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: SCREEN_URL,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      timeout: TIMEOUT_MS,
    });
    return { success: true };
  } catch (e) {
    const status = e.httpCode || e.statusCode || (e.response && e.response.status);
    const transient = status === 429 || (status >= 500 && status < 600) || !status;
    if (transient && attempt < MAX_RETRIES) {
      const retryAfter = e.response && e.response.headers && (e.response.headers['retry-after'] || (e.response.headers.get && e.response.headers.get('retry-after')));
      const raMs = retryAfter ? Math.max(50, Number(retryAfter) * 1000) : 0;
      const backoff = Math.min(30000, 1000 * Math.pow(2, attempt)) + Math.floor(Math.random() * 250);
      await new Promise(function (r) { setTimeout(r, raMs || backoff); });
      return forwardOne(payload, attempt + 1);
    }
    return { success: false, status: status, message: String(e.message || e).slice(0, 400) };
  }
}

for (let i = 0; i < grants.length; i++) {
  const g = grants[i];
  const result = await forwardOne(g);
  if (result.success) {
    ok++;
  } else {
    failed++;
    errors.push({ grantid: g && g.grantid, status: result.status, message: result.message });
  }
  if (i < grants.length - 1) {
    await new Promise(function (r) { setTimeout(r, DELAY_MS); });
  }
}

return [{ json: { success: true, total: grants.length, forwarded: ok, failed: failed, errors: errors } }];
